import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Häufig gestellte Fragen","description":"Fragen über Fabric, die häufig von Spielern und Server Administratoren gestellt werden.","frontmatter":{"title":"Häufig gestellte Fragen","description":"Fragen über Fabric, die häufig von Spielern und Server Administratoren gestellt werden.","files":[]},"headers":[],"relativePath":"de_de/players/faq.md","filePath":"translated/de_de/players/faq.md","lastUpdated":1770561656000}`);var a={name:`de_de/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Häufig gestellte Fragen <a class="header-anchor" href="#h1" aria-label="Permalink to “Häufig gestellte Fragen”">​</a></h1><p>Es gibt viele Fragen, die häufig gestellt werden, deshalb haben wir hier eine Liste dieser Fragen zusammengestellt.</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Welche Minecraft Versionen werden von Fabric unterstützt? <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Welche Minecraft Versionen werden von Fabric unterstützt?”">​</a></h2><p>Offiziell unterstützt Fabric alle Minecraft-Versionen, beginnend mit Snapshot <code>18w43b</code> und höher, sowie Vollversionen beginnend mit Version <code>1.14</code> und höher.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">Wo kann ich veröffentlichte Fabric-Mods herunterladen? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “Wo kann ich veröffentlichte Fabric-Mods herunterladen?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Du solltest immer prüfen, ob Mods aus einer vertrauenswürdigen Quelle stammen. Weitere Informationen zum Finden von Mods findest du in dem Leitfaden <a href="./finding-mods">Vertrauenswürdige Mods finden</a>.</p></div><p>Die meisten Autoren veröffentlichen ihre Mods auf <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> und <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, manche laden sie jedoch auch auf ihre persönliche Website oder auf andere Plattformen wie GitHub hoch.</p><h2 id="where-can-i-find-pre-made-fabric-modpacks" tabindex="-1">Wo kann ich vorgefertige Fabric-Modpacks herunterladen? <a class="header-anchor" href="#where-can-i-find-pre-made-fabric-modpacks" aria-label="Permalink to “Wo kann ich vorgefertige Fabric-Modpacks herunterladen?”">​</a></h2><p>Du kannst vorgefertigte Fabric-Modpacks auf einer Vielzahl von Plattformen finden, wie beispielsweise:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};